code = """import json
import pandas as pd
import re

# Load data
with open(locals()['var_function-call-5745013072120517223'], 'r') as f:
    businesses = json.load(f)

with open(locals()['var_function-call-9186963928583799241'], 'r') as f:
    reviews = json.load(f)

# Process Businesses
# Regex: matches ", XX, this"
state_pattern = re.compile(r",\s([A-Z]{2}),\sthis")

data = []
for b in businesses:
    desc = b.get('description', '')
    match = state_pattern.search(desc)
    state = match.group(1) if match else None
    
    bid = b.get('business_id', '')
    if bid.startswith('businessid_'):
        bref = 'businessref_' + bid.split('_')[1]
    else:
        bref = bid 
        
    data.append({
        'business_ref': bref,
        'review_count': int(b.get('review_count', 0)),
        'state': state
    })

df_b = pd.DataFrame(data)

# Filter out rows where state wasn't found
df_b = df_b.dropna(subset=['state'])

# 1. Find state with highest number of reviews
# Sum review_count by state
state_reviews = df_b.groupby('state')['review_count'].sum().sort_values(ascending=False)
top_state = state_reviews.index[0]
top_reviews_count = state_reviews.iloc[0]

print(f"Top State: {top_state} with {top_reviews_count} reviews (metadata sum)")
print("State Reviews Breakdown:")
print(state_reviews)

# 2. Calculate average rating of businesses in that state
top_state_businesses = df_b[df_b['state'] == top_state]
print(f"Number of businesses in {top_state}: {len(top_state_businesses)}")

# Prepare reviews
df_r = pd.DataFrame(reviews)
df_r['rating'] = pd.to_numeric(df_r['rating'])

# Merge
merged = pd.merge(top_state_businesses, df_r, on='business_ref', how='inner')
print(f"Number of reviews found for {top_state}: {len(merged)}")

# Average rating of businesses
# First, calc avg per business
business_avgs = merged.groupby('business_ref')['rating'].mean()
# Then avg of those
avg_rating_per_business = business_avgs.mean()

print(f"Average rating (per business): {avg_rating_per_business}")

result = {
    "state": top_state,
    "total_reviews_metadata": int(top_reviews_count),
    "average_rating": avg_rating_per_business
}

print("__RESULT__:")
print(json.dumps(result))"""

